# This is a memory aid, not an SDK dependency.
ado = {
    'organization': 'contoso',
    'project': 'SpaceElevator',
    'services': ['Boards', 'Repos', 'Pipelines', 'Test Plans', 'Artifacts'],
}

for service in ado['services']:
    print(f"{ado['organization']}/{ado['project']} has {service}")

# Representative configs as Python dictionaries.
remote_mcp = {
    'type': 'http',
    'url': 'https://mcp.dev.azure.com/contoso',
    'headers': {'X-MCP-Toolsets': 'repos,wit,pipelines', 'X-MCP-Readonly': 'true'},
}

local_stdio = {
    'type': 'stdio',
    'command': 'npx',
    'args': ['-y', '@azure-devops/mcp', 'contoso', '-d', 'core', 'work-items', 'repositories'],
}
print(remote_mcp)
print(local_stdio)

required_permissions = {
    'list_active_bugs': ['View work items'],
    'create_task': ['View work items', 'Edit work items in this node'],
    'list_pipeline_runs': ['View builds'],
    'queue_pipeline': ['View builds', 'Queue builds'],
}

for scenario, permissions in required_permissions.items():
    print(scenario, 'needs', ', '.join(permissions))

prompts = {
    'list my active bugs': {
        'tool': 'wit_work_item',
        'action': 'query or my',
        'risk': 'read',
        'args': {'workItemType': 'Bug', 'stateNot': 'Closed'},
    },
    'create a task': {
        'tool': 'wit_work_item_write',
        'action': 'create',
        'risk': 'write approval required',
        'args': {'type': 'Task', 'title': '<from user>'},
    },
    'show recent pipeline runs': {
        'tool': 'pipelines_run',
        'action': 'list',
        'risk': 'read',
        'args': {'project': '<project>', 'pipelineId': '<optional>'},
    },
    'open a PR': {
        'tool': 'repo_pull_request_write',
        'action': 'create',
        'risk': 'write approval required',
        'args': {'repository': '<repo>', 'sourceRefName': '<branch>', 'targetRefName': 'main'},
    },
}
for text, plan in prompts.items():
    print(text, '=>', plan['tool'], plan['action'], plan['risk'])

# These dictionaries illustrate the shape an agent sends to MCP.
# Actual tool names are discovered from the connected server.
tool_calls = [
    {
        'name': 'wit_work_item',
        'arguments': {'action': 'query_by_wiql', 'project': 'SpaceElevator', 'wiql': "SELECT [System.Id] FROM WorkItems WHERE [System.WorkItemType] = 'Bug'"},
        'expected_result': {'workItems': [{'id': 101}, {'id': 102}]},
    },
    {
        'name': 'wit_work_item_write',
        'arguments': {'action': 'create', 'project': 'SpaceElevator', 'type': 'Task', 'fields': {'System.Title': 'Add tests'}},
        'expected_result': {'id': 131489, 'fields': {'System.State': 'New'}},
    },
    {
        'name': 'pipelines_run',
        'arguments': {'action': 'list', 'project': 'SpaceElevator', 'pipelineId': 42, 'top': 5},
        'expected_result': {'runs': [{'id': 9001, 'state': 'completed'}]},
    },
    {
        'name': 'repo_pull_request',
        'arguments': {'action': 'list', 'project': 'SpaceElevator', 'repository': 'flight-code', 'status': 'active'},
        'expected_result': {'pullRequests': [{'pullRequestId': 77, 'status': 'active'}]},
    },
]
for call in tool_calls:
    print(call['name'], call['arguments'])

write_tools = {'wit_work_item_write', 'repo_pull_request_write', 'pipelines_write', 'wiki_upsert_page'}

def approval_required(tool_name: str) -> bool:
    return tool_name in write_tools or tool_name.endswith('_write')

for name in ['wit_work_item', 'wit_work_item_write', 'pipelines_run', 'pipelines_write']:
    print(name, 'approval required:', approval_required(name))
